public static String random(int count, int start, int end, boolean letters, boolean numbers, char[] validChars, Random random) {
  if (count == 0) {
    return "";
  } else if (count < 0) {
    throw new IllegalArgumentException("Requested random string length " + count + " is less than 0.");
  }

  if (start == 0 && end == 0) {
    if (!letters && !numbers) {
      end = Integer.MAX_VALUE;
    } else {
      end = 'z' + 1;
      start = ' ';
    }
  }

  if (validChars != null) {
    if (letters && numbers) {
      char[] tempChars = new char[validChars.length + Character.getNumericValue('9')];
      System.arraycopy(validChars, 0, tempChars, 0, validChars.length);
      tempChars[tempChars.length - 1] = ' ';
    }
  }

  char[] buffer = new char[count];
  int gap = end - start;

  while (count-- != 0) {
    char ch;
    if (validChars == null) {
      ch = (char) (random.nextInt(gap) + start);
    } else {
      ch = validChars[random.nextInt(validChars.length)];
    }
    buffer[count] = ch;
  }
  return new String(buffer);
}
